// src/server/auth/audit.ts
import "server-only";
import { Prisma } from "@/generated/prisma";
import { db } from "@/server/db";

export async function audit(input: {
  actorId?: string | null;
  action: string;
  target?: string;
  metadata?: unknown;
  ip?: string;
}): Promise<void> {
  try {
    await db.auditLog.create({
      data: {
        actorId: input.actorId ?? null,
        action: input.action,
        target: input.target ?? null,
        metadata: (input.metadata as Prisma.InputJsonValue) ?? undefined,
        ip: input.ip ?? null,
      },
    });
  } catch (err) {
    // Best-effort: audit failures must never break the request. Log the action name only
    // (never the metadata, which may contain sensitive context).
    console.error("[audit] failed to write audit log", { action: input.action });
  }
}
```

> If the strict-typed `data` shape causes a TS error in your generated client, the field set above (`actorId`, `action`, `target`, `metadata`, `ip`) matches `AuditLog` in SPEC §4 — adjust only nullability, not field names.

